"use server";

import { prisma } from "@/lib/prisma";

export type TransactionListItem = {
  id: number;
  type: string;
  counterpartyId: number;
  counterpartyName: string;
  expenseCategoryId: number;
  expenseCategoryName: string;
  costCenterName: string | null;
  allocationTemplateName: string | null;
  amount: number;
  taxAmount: number;
  taxRate: number;
  taxType: string;
  periodFrom: string;
  periodTo: string;
  paymentDueDate: string | null;
  status: string;
  note: string | null;
  isAutoGenerated: boolean;
  sourceType: string | null;
  invoiceGroupId: number | null;
  paymentGroupId: number | null;
  contractId: number | null;
  createdByName: string;
  createdAt: string;
  updatedAt: string;
};

export type TransactionFilters = {
  type?: "revenue" | "expense";
  status?: string;
  counterpartyId?: number;
  periodFrom?: string;
  periodTo?: string;
};

export type TransactionSort = {
  field: string;
  direction: "asc" | "desc";
};

/** サーバーサイドページネーション導入時に使用予定 */
export async function listTransactions(
  filters?: TransactionFilters,
  sort?: TransactionSort
): Promise<TransactionListItem[]> {
  const where: Record<string, unknown> = {
    deletedAt: null,
    // STPプロジェクトの取引のみ（projectId=1 or projectId=null で STP関連）
    // 将来的にはプロジェクトIDで絞り込む
  };

  if (filters?.type) {
    where.type = filters.type;
  }
  if (filters?.status) {
    where.status = filters.status;
  }
  if (filters?.counterpartyId) {
    where.counterpartyId = filters.counterpartyId;
  }
  if (filters?.periodFrom) {
    where.periodFrom = { gte: new Date(filters.periodFrom) };
  }
  if (filters?.periodTo) {
    where.periodTo = { lte: new Date(filters.periodTo) };
  }

  const orderBy: Record<string, string>[] = [];
  if (sort?.field) {
    orderBy.push({ [sort.field]: sort.direction });
  } else {
    orderBy.push({ periodFrom: "desc" }, { id: "desc" });
  }

  const records = await prisma.transaction.findMany({
    where,
    include: {
      counterparty: true,
      expenseCategory: true,
      costCenter: true,
      allocationTemplate: true,
      creator: true,
    },
    orderBy,
  });

  return records.map((r) => mapTransactionRecord(r));
}

/** 削除済み取引一覧を取得 */
export async function listDeletedTransactions(): Promise<TransactionListItem[]> {
  const records = await prisma.transaction.findMany({
    where: {
      deletedAt: { not: null },
    },
    include: {
      counterparty: true,
      expenseCategory: true,
      costCenter: true,
      allocationTemplate: true,
      creator: true,
    },
    orderBy: [{ deletedAt: "desc" }, { id: "desc" }],
  });

  return records.map((r) => mapTransactionRecord(r));
}

/** レコードをTransactionListItemに変換するヘルパー */
function mapTransactionRecord(r: {
  id: number;
  type: string;
  counterpartyId: number;
  counterparty: { name: string };
  expenseCategoryId: number;
  expenseCategory: { name: string };
  costCenter: { name: string } | null;
  allocationTemplate: { name: string } | null;
  amount: number;
  taxAmount: number;
  taxRate: number;
  taxType: string;
  periodFrom: Date;
  periodTo: Date;
  paymentDueDate: Date | null;
  status: string;
  note: string | null;
  isAutoGenerated: boolean;
  sourceType: string | null;
  invoiceGroupId: number | null;
  paymentGroupId: number | null;
  contractId: number | null;
  creator: { name: string };
  createdAt: Date;
  updatedAt: Date;
}): TransactionListItem {
  return {
    id: r.id,
    type: r.type,
    counterpartyId: r.counterpartyId,
    counterpartyName: r.counterparty.name,
    expenseCategoryId: r.expenseCategoryId,
    expenseCategoryName: r.expenseCategory.name,
    costCenterName: r.costCenter?.name ?? null,
    allocationTemplateName: r.allocationTemplate?.name ?? null,
    amount: r.amount,
    taxAmount: r.taxAmount,
    taxRate: r.taxRate,
    taxType: r.taxType,
    periodFrom: r.periodFrom.toISOString().split("T")[0],
    periodTo: r.periodTo.toISOString().split("T")[0],
    paymentDueDate: r.paymentDueDate
      ? r.paymentDueDate.toISOString().split("T")[0]
      : null,
    status: r.status,
    note: r.note,
    isAutoGenerated: r.isAutoGenerated,
    sourceType: r.sourceType,
    invoiceGroupId: r.invoiceGroupId,
    paymentGroupId: r.paymentGroupId,
    contractId: r.contractId,
    createdByName: r.creator.name,
    createdAt: r.createdAt.toISOString().split("T")[0],
    updatedAt: r.updatedAt.toISOString().split("T")[0],
  };
}

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { TransactionsTable } from "./transactions-table";
import { listTransactions, listDeletedTransactions } from "./actions";

export default async function TransactionsPage() {
  const [data, deletedData] = await Promise.all([
    listTransactions(),
    listDeletedTransactions(),
  ]);

  // 取引先オプション（重複除去）
  const counterpartyMap = new Map<string, string>();
  for (const r of data) {
    counterpartyMap.set(String(r.counterpartyId), r.counterpartyName);
  }
  const counterpartyOptions = Array.from(counterpartyMap.entries()).map(
    ([value, label]) => ({ value, label })
  );

  // サマリー計算
  const calcTaxIncluded = (r: { amount: number; taxAmount: number; taxType: string }) =>
    r.taxType === "tax_excluded" ? r.amount + r.taxAmount : r.amount;
  const totalRevenue = data
    .filter((r) => r.type === "revenue")
    .reduce((sum, r) => sum + calcTaxIncluded(r), 0);
  const totalExpense = data
    .filter((r) => r.type === "expense")
    .reduce((sum, r) => sum + calcTaxIncluded(r), 0);
  const unconfirmedCount = data.filter((r) => r.status === "unconfirmed").length;

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">取引一覧</h1>

      <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
        <Card>
          <CardContent className="pt-6">
            <div className="text-sm text-muted-foreground">売上合計（税込）</div>
            <div className="text-2xl font-bold text-emerald-600">
              ¥{totalRevenue.toLocaleString()}
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="text-sm text-muted-foreground">経費合計（税込）</div>
            <div className="text-2xl font-bold text-rose-600">
              ¥{totalExpense.toLocaleString()}
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="text-sm text-muted-foreground">未確定</div>
            <div className="text-2xl font-bold text-orange-600">
              {unconfirmedCount}件
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>取引一覧</CardTitle>
        </CardHeader>
        <CardContent>
          <TransactionsTable
            data={data}
            deletedData={deletedData}
            counterpartyOptions={counterpartyOptions}
          />
        </CardContent>
      </Card>
    </div>
  );
}

