 11→
 12→// ============================================
 13→// 税額計算ヘルパー（仕様9.1準拠: 税率別グループ小計→一括税額計算）
 14→// ============================================
 15→
 16→function calcGroupTotals(transactions: { amount: number; taxAmount: number; taxRate: number; taxType: string }[]) {
 17→  const lineItems = transactions.map((t) => ({
 18→    amount: t.taxType === "tax_excluded" ? t.amount : t.amount - t.taxAmount,
 19→    taxRate: t.taxRate,
 20→  }));
 21→  const taxSummary = calcInvoiceTaxSummary(lineItems);
 22→  const { totalAmount, taxAmount } = calcInvoiceTotalFromSummary(taxSummary);
 23→  return { subtotal: totalAmount - taxAmount, taxAmount, totalAmount };
 24→}
