 26→// ============================================
 27→// 型定義
 28→// ============================================
 29→
 30→export type InvoiceGroupListItem = {
 31→  id: number;
 32→  counterpartyId: number;
 33→  counterpartyName: string;
 34→  operatingCompanyId: number;
 35→  operatingCompanyName: string;
 36→  bankAccountId: number | null;
 37→  bankAccountLabel: string | null;
 38→  invoiceNumber: string | null;
 39→  invoiceDate: string | null;
 40→  paymentDueDate: string | null;
 41→  subtotal: number | null;
 42→  taxAmount: number | null;
 43→  totalAmount: number | null;
 44→  pdfPath: string | null;
 45→  status: string;
 46→  correctionType: string | null;
 47→  originalInvoiceGroupId: number | null;
 48→  originalInvoiceNumber: string | null;
 49→  transactionCount: number;
 50→  createdByName: string;
 51→  createdAt: string;
 52→};
 53→
 54→export type UngroupedTransaction = {
 55→  id: number;
 56→  type: string;
 57→  counterpartyId: number;
 58→  counterpartyName: string;
 59→  expenseCategoryName: string;
 60→  amount: number;
 61→  taxAmount: number;
 62→  taxRate: number;
 63→  taxType: string;
 64→  periodFrom: string;
 65→  periodTo: string;
 66→  note: string | null;
 67→};
 68→
 69→// ============================================
 70→// 一覧取得
 71→// ============================================
 72→
 73→export async function getInvoiceGroups(): Promise<InvoiceGroupListItem[]> {
 74→  const records = await prisma.invoiceGroup.findMany({
 75→    where: { deletedAt: null },
 76→    include: {
 77→      counterparty: true,
 78→      operatingCompany: true,
 79→      bankAccount: true,
 80→      originalInvoiceGroup: { select: { invoiceNumber: true } },
 81→      transactions: { where: { deletedAt: null }, select: { id: true } },
 82→      creator: true,
 83→    },
 84→    orderBy: [{ createdAt: "desc" }, { id: "desc" }],
 85→  });
 86→
 87→  return records.map((r) => ({
 88→    id: r.id,
 89→    counterpartyId: r.counterpartyId,
 90→    counterpartyName: r.counterparty.name,
 91→    operatingCompanyId: r.operatingCompanyId,
 92→    operatingCompanyName: r.operatingCompany.companyName,
 93→    bankAccountId: r.bankAccountId,
 94→    bankAccountLabel: r.bankAccount
 95→      ? `${r.bankAccount.bankName} ${r.bankAccount.branchName} ${r.bankAccount.accountNumber}`
 96→      : null,
 97→    invoiceNumber: r.invoiceNumber,
 98→    invoiceDate: r.invoiceDate?.toISOString().split("T")[0] ?? null,
 99→    paymentDueDate: r.paymentDueDate?.toISOString().split("T")[0] ?? null,
100→    subtotal: r.subtotal,
101→    taxAmount: r.taxAmount,
102→    totalAmount: r.totalAmount,
103→    pdfPath: r.pdfPath,
104→    status: r.status,
105→    correctionType: r.correctionType,
106→    originalInvoiceGroupId: r.originalInvoiceGroupId,
107→    originalInvoiceNumber: r.originalInvoiceGroup?.invoiceNumber ?? null,
108→    transactionCount: r.transactions.length,
109→    createdByName: r.creator.name,
110→    createdAt: r.createdAt.toISOString().split("T")[0],
111→  }));
112→}
113→
114→// 確認済み＆未グループ化の売上取引を取得
115→export async function getUngroupedTransactions(
116→  counterpartyId?: number
117→): Promise<UngroupedTransaction[]> {
118→  const where: Record<string, unknown> = {
119→    deletedAt: null,
120→    type: "revenue",
121→    status: "confirmed",
122→    invoiceGroupId: null,
123→  };
124→  if (counterpartyId) {
125→    where.counterpartyId = counterpartyId;
126→  }
127→
128→  const records = await prisma.transaction.findMany({
129→    where,
130→    include: {
131→      counterparty: true,
132→      expenseCategory: true,
133→    },
134→    orderBy: [{ periodFrom: "asc" }, { id: "asc" }],
135→  });
136→
137→  return records.map((r) => ({
138→    id: r.id,
139→    type: r.type,
140→    counterpartyId: r.counterpartyId,
141→    counterpartyName: r.counterparty.name,
142→    expenseCategoryName: r.expenseCategory.name,
143→    amount: r.amount,
144→    taxAmount: r.taxAmount,
145→    taxRate: r.taxRate,
146→    taxType: r.taxType,
147→    periodFrom: r.periodFrom.toISOString().split("T")[0],
148→    periodTo: r.periodTo.toISOString().split("T")[0],
149→    note: r.note,
150→  }));
151→}
152→
153→// ============================================
154→// 作成
155→// ============================================
156→
157→export async function createInvoiceGroup(data: {
158→  counterpartyId: number;
159→  operatingCompanyId: number;
160→  bankAccountId?: number | null;
161→  invoiceDate?: string | null;
162→  paymentDueDate?: string | null;
163→  transactionIds: number[];
164→}): Promise<{ id: number; invoiceNumber: string | null }> {
165→  const user = await requireEdit("stp");
166→
167→  const result = await prisma.$transaction(async (tx) => {
168→    // 選択された取引の金額を集計
169→    const transactions = await tx.transaction.findMany({
170→      where: {
171→        id: { in: data.transactionIds },
172→        deletedAt: null,
173→        status: "confirmed",
174→        invoiceGroupId: null,
175→        type: "revenue",
176→      },
177→    });
178→
179→    if (transactions.length === 0) {
180→      throw new Error("グループ化できる取引がありません");
181→    }
182→
183→    // 全取引が同一取引先か確認
184→    const counterpartyIds = new Set(transactions.map((t) => t.counterpartyId));
185→    if (counterpartyIds.size > 1) {
186→      throw new Error("異なる取引先の取引は同じ請求グループに入れられません");
187→    }
188→    if (!counterpartyIds.has(data.counterpartyId)) {
189→      throw new Error("取引先が一致しません");
190→    }
191→
192→    // 金額計算（仕様9.1準拠: 税率別グループ小計→一括税額計算）
193→    const { subtotal, taxAmount, totalAmount } = calcGroupTotals(transactions);
194→
195→    // InvoiceGroup作成
196→    const group = await tx.invoiceGroup.create({
197→      data: {
198→        counterpartyId: data.counterpartyId,
199→        operatingCompanyId: data.operatingCompanyId,
200→        bankAccountId: data.bankAccountId ?? null,
201→        invoiceDate: data.invoiceDate ? new Date(data.invoiceDate) : null,
202→        paymentDueDate: data.paymentDueDate
203→          ? new Date(data.paymentDueDate)
204→          : null,
205→        subtotal,
206→        taxAmount,
207→        totalAmount,
208→        status: "draft",
209→        createdBy: user.id,
210→      },
211→    });
212→
213→    // 取引をグループに紐づけ
214→    await tx.transaction.updateMany({
215→      where: { id: { in: data.transactionIds } },
216→      data: { invoiceGroupId: group.id },
217→    });
218→
219→    return { id: group.id, invoiceNumber: null };
220→  });
221→
222→  revalidatePath("/stp/finance/invoices");
223→  revalidatePath("/stp/finance/transactions");
224→  return result;
225→}
226→
227→// ============================================
228→// 更新
229→// ============================================
230→
231→export async function updateInvoiceGroup(
232→  id: number,
233→  data: {
234→    bankAccountId?: number | null;
235→    invoiceDate?: string | null;
236→    paymentDueDate?: string | null;
237→    subtotal?: number | null;
238→    taxAmount?: number | null;
239→    totalAmount?: number | null;
240→  }
241→): Promise<void> {
242→  const user = await requireEdit("stp");
243→
244→  const group = await prisma.invoiceGroup.findUnique({
245→    where: { id, deletedAt: null },
246→  });
247→  if (!group) throw new Error("請求グループが見つかりません");
248→
249→  // 送付済み以降・返送は編集不可（returnedはdraftに戻してから編集）
250→  if (["sent", "awaiting_accounting", "partially_paid", "paid", "corrected", "returned"].includes(group.status)) {
251→    throw new Error("このステータスでは編集できません");
252→  }
253→
254→  const updateData: Record<string, unknown> = {
255→    updatedBy: user.id,
256→  };
257→
258→  if ("bankAccountId" in data)
259→    updateData.bankAccountId = data.bankAccountId ?? null;
260→  if ("invoiceDate" in data)
261→    updateData.invoiceDate = data.invoiceDate
262→      ? new Date(data.invoiceDate)
263→      : null;
264→  if ("paymentDueDate" in data)
265→    updateData.paymentDueDate = data.paymentDueDate
266→      ? new Date(data.paymentDueDate)
267→      : null;
268→  if ("subtotal" in data) updateData.subtotal = data.subtotal;
269→  if ("taxAmount" in data) updateData.taxAmount = data.taxAmount;
270→  if ("totalAmount" in data) updateData.totalAmount = data.totalAmount;
271→
272→  // pdf_created状態で情報が変更された場合、ステータスをdraftに戻す
273→  if (group.status === "pdf_created") {
274→    updateData.pdfPath = null;
275→    updateData.pdfFileName = null;
276→    updateData.status = "draft";
277→  }
278→
279→  await prisma.invoiceGroup.update({
280→    where: { id },
281→    data: updateData,
282→  });
283→
284→  revalidatePath("/stp/finance/invoices");
285→}
286→
287→// ============================================
288→// 取引の追加・削除
289→// ============================================
290→
291→export async function addTransactionToGroup(
292→  groupId: number,
293→  transactionIds: number[]
294→): Promise<void> {
295→  const user = await requireEdit("stp");
296→
297→  const group = await prisma.invoiceGroup.findUnique({
298→    where: { id: groupId, deletedAt: null },
299→    include: { transactions: { where: { deletedAt: null } } },
300→  });
301→  if (!group) throw new Error("請求グループが見つかりません");
302→
303→  // 下書き・PDF作成済みのみ追加可能
304→  if (!["draft", "pdf_created"].includes(group.status)) {
305→    throw new Error("このステータスでは取引を追加できません");
306→  }
307→
308→  // 追加する取引を検証
309→  const transactions = await prisma.transaction.findMany({
310→    where: {
311→      id: { in: transactionIds },
312→      deletedAt: null,
313→      status: "confirmed",
314→      invoiceGroupId: null,
315→      type: "revenue",
316→      counterpartyId: group.counterpartyId,
317→    },
318→  });
319→
320→  if (transactions.length === 0) {
321→    throw new Error("追加できる取引がありません");
322→  }
323→
324→  await prisma.$transaction(async (tx) => {
325→    // 取引をグループに紐づけ
326→    await tx.transaction.updateMany({
327→      where: { id: { in: transactions.map((t) => t.id) } },
328→      data: { invoiceGroupId: groupId },
329→    });
330→
331→    // 金額再計算（仕様9.1準拠）
332→    const allTransactions = [
333→      ...group.transactions,
334→      ...transactions,
335→    ];
336→    const { subtotal, taxAmount, totalAmount } = calcGroupTotals(allTransactions);
337→
338→    const updateData: Record<string, unknown> = {
339→      subtotal,
340→      taxAmount,
341→      totalAmount,
342→      updatedBy: user.id,
343→    };
344→
345→    // pdf_created時はPDFを無効化
346→    if (group.status === "pdf_created") {
347→      updateData.pdfPath = null;
348→      updateData.pdfFileName = null;
349→      updateData.status = "draft";
350→    }
351→
352→    await tx.invoiceGroup.update({
353→      where: { id: groupId },
354→      data: updateData,
355→    });
356→  });
357→
358→  revalidatePath("/stp/finance/invoices");
359→  revalidatePath("/stp/finance/transactions");
360→}
361→
362→export async function removeTransactionFromGroup(
363→  groupId: number,
364→  transactionId: number
365→): Promise<void> {
366→  const user = await requireEdit("stp");
367→
368→  const group = await prisma.invoiceGroup.findUnique({
369→    where: { id: groupId, deletedAt: null },
370→    include: { transactions: { where: { deletedAt: null } } },
371→  });
372→  if (!group) throw new Error("請求グループが見つかりません");
373→
374→  // 下書き・PDF作成済みのみ削除可能
375→  if (!["draft", "pdf_created"].includes(group.status)) {
376→    throw new Error("このステータスでは取引を削除できません");
377→  }
378→
379→  await prisma.$transaction(async (tx) => {
380→    // 取引のグループ紐付けを解除（所属グループを検証）
381→    await tx.transaction.update({
382→      where: { id: transactionId, invoiceGroupId: groupId },
383→      data: { invoiceGroupId: null },
384→    });
385→
386→    // 金額再計算（仕様9.1準拠）
387→    const remaining = group.transactions.filter(
388→      (t) => t.id !== transactionId
389→    );
390→    const { subtotal, taxAmount, totalAmount } = calcGroupTotals(remaining);
391→
392→    const updateData: Record<string, unknown> = {
393→      subtotal,
394→      taxAmount,
395→      totalAmount,
396→      updatedBy: user.id,
397→    };
398→
399→    // pdf_created時はPDFを無効化
400→    if (group.status === "pdf_created") {
401→      updateData.pdfPath = null;
402→      updateData.pdfFileName = null;
403→      updateData.status = "draft";
404→    }
405→
406→    await tx.invoiceGroup.update({
407→      where: { id: groupId },
408→      data: updateData,
409→    });
410→  });
411→
412→  revalidatePath("/stp/finance/invoices");
413→  revalidatePath("/stp/finance/transactions");
414→}
415→
416→// ============================================
417→// 削除（論理削除）
418→// ============================================
419→
420→export async function deleteInvoiceGroup(
421→  id: number,
422→  deleteTransactions?: boolean
423→): Promise<void> {
424→  const user = await requireEdit("stp");
425→
426→  const group = await prisma.invoiceGroup.findUnique({
427→    where: { id, deletedAt: null },
428→  });
429→  if (!group) throw new Error("請求グループが見つかりません");
430→
431→  // 下書き・PDF作成済みのみ削除可能
432→  if (!["draft", "pdf_created"].includes(group.status)) {
433→    throw new Error("下書きまたはPDF作成済みの請求グループのみ削除できます");
434→  }
435→
436→  await prisma.$transaction(async (tx) => {
437→    if (deleteTransactions) {
438→      // 取引も論理削除
439→      await tx.transaction.updateMany({
440→        where: { invoiceGroupId: id, deletedAt: null },
441→        data: { deletedAt: new Date(), invoiceGroupId: null },
442→      });
443→    } else {
444→      // 取引のグループ紐付けを解除
445→      await tx.transaction.updateMany({
446→        where: { invoiceGroupId: id },
447→        data: { invoiceGroupId: null },
448→      });
449→    }
450→
451→    // 論理削除
452→    await tx.invoiceGroup.update({
453→      where: { id },
454→      data: { deletedAt: new Date(), updatedBy: user.id },
455→    });
456→  });
457→
458→  revalidatePath("/stp/finance/invoices");
459→  revalidatePath("/stp/finance/transactions");
460→}
461→
462→// ============================================
463→// 訂正請求書の作成
464→// ============================================
465→
466→export async function createCorrectionInvoiceGroup(
467→  originalId: number,
468→  correctionType: "replacement" | "additional"
469→): Promise<{ id: number }> {
470→  const user = await requireEdit("stp");
471→
472→  const original = await prisma.invoiceGroup.findUnique({
473→    where: { id: originalId, deletedAt: null },
474→    include: { transactions: { where: { deletedAt: null } } },
475→  });
476→  if (!original) throw new Error("元の請求グループが見つかりません");
477→
478→  // 送付済み以降のみ訂正可能
479→  if (!["sent", "awaiting_accounting"].includes(original.status)) {
480→    throw new Error("送付済みまたは経理処理待ちの請求グループのみ訂正できます");
481→  }
482→
483→  const result = await prisma.$transaction(async (tx) => {
484→    // 訂正請求書を作成
485→    const correction = await tx.invoiceGroup.create({
486→      data: {
487→        counterpartyId: original.counterpartyId,
488→        operatingCompanyId: original.operatingCompanyId,
489→        bankAccountId: original.bankAccountId,
490→        invoiceDate: null,
491→        paymentDueDate: original.paymentDueDate,
492→        originalInvoiceGroupId: originalId,
493→        correctionType,
494→        status: "draft",
495→        createdBy: user.id,
496→      },
497→    });
498→
499→    // 差し替えの場合: 元の取引を新しいグループに移動
500→    if (correctionType === "replacement") {
501→      await tx.transaction.updateMany({
502→        where: { id: { in: original.transactions.map((t) => t.id) } },
503→        data: { invoiceGroupId: correction.id },
504→      });
505→
506→      // 金額を引き継ぎ
507→      await tx.invoiceGroup.update({
508→        where: { id: correction.id },
509→        data: {
510→          subtotal: original.subtotal,
511→          taxAmount: original.taxAmount,
512→          totalAmount: original.totalAmount,
513→        },
514→      });
515→    }
516→
517→    // 元の請求グループを「訂正済み」に
518→    await tx.invoiceGroup.update({
519→      where: { id: originalId },
520→      data: {
521→        status: "corrected",
522→        updatedBy: user.id,
523→      },
524→    });
525→
526→    return { id: correction.id };
527→  });
528→
529→  revalidatePath("/stp/finance/invoices");
530→  revalidatePath("/stp/finance/transactions");
531→  return result;
532→}
533→
534→// ============================================
535→// 請求書番号の採番（PDF作成時）
536→// ============================================
537→
538→export async function assignInvoiceNumber(
539→  groupId: number
540→): Promise<string> {
541→  const user = await requireEdit("stp");
542→
543→  const result = await prisma.$transaction(async (tx) => {
544→    const group = await tx.invoiceGroup.findUnique({
545→      where: { id: groupId, deletedAt: null },
546→    });
547→    if (!group) throw new Error("請求グループが見つかりません");
548→
549→    // 既に採番済みならそのまま返す
550→    if (group.invoiceNumber) return group.invoiceNumber;
551→
552→    const invoiceNumber = await generateInvoiceGroupNumber(
553→      group.operatingCompanyId,
554→      tx
555→    );
556→
557→    const oldStatus = group.status;
558→    await tx.invoiceGroup.update({
559→      where: { id: groupId },
560→      data: {
561→        invoiceNumber,
562→        status: "pdf_created",
563→        updatedBy: user.id,
564→      },
565→    });
566→
567→    await recordChangeLog(
568→      {
569→        tableName: "InvoiceGroup",
570→        recordId: groupId,
571→        changeType: "update",
572→        oldData: { status: oldStatus },
573→        newData: { status: "pdf_created" },
574→      },
575→      user.id,
576→      tx
577→    );
578→
579→    return invoiceNumber;
580→  });
581→
582→  revalidatePath("/stp/finance/invoices");
583→  return result;
584→}
585→
586→// ============================================
587→// ステータス変更
588→// ============================================
589→
590→export async function updateInvoiceGroupStatus(
591→  id: number,
592→  newStatus: string
593→): Promise<void> {
594→  const user = await requireEdit("stp");
595→
596→  const group = await prisma.invoiceGroup.findUnique({
597→    where: { id, deletedAt: null },
598→  });
599→  if (!group) throw new Error("請求グループが見つかりません");
600→
601→  // 遷移バリデーション
602→  const validTransitions: Record<string, string[]> = {
603→    draft: ["pdf_created"],
604→    pdf_created: ["draft", "sent"],
605→    sent: ["awaiting_accounting", "corrected"],
606→    awaiting_accounting: ["partially_paid", "paid", "returned", "corrected"],
607→    partially_paid: ["paid"],
608→    returned: ["draft"],
609→  };
610→
611→  const allowed = validTransitions[group.status] ?? [];
612→  if (!allowed.includes(newStatus)) {
613→    throw new Error(
614→      `ステータスを「${group.status}」から「${newStatus}」に変更できません`
615→    );
616→  }
617→
618→  // pdf_created への遷移時に採番
619→  if (newStatus === "pdf_created" && !group.invoiceNumber) {
620→    await assignInvoiceNumber(id);
621→    return;
622→  }
623→
624→  const oldStatus = group.status;
625→  await prisma.$transaction(async (tx) => {
626→    await tx.invoiceGroup.update({
627→      where: { id },
628→      data: { status: newStatus, updatedBy: user.id },
629→    });
630→
631→    await recordChangeLog(
632→      {
633→        tableName: "InvoiceGroup",
634→        recordId: id,
635→        changeType: "update",
636→        oldData: { status: oldStatus },
637→        newData: { status: newStatus },
638→      },
639→      user.id,
640→      tx
641→    );
642→  });
643→
644→  revalidatePath("/stp/finance/invoices");
645→}
646→
647→// ============================================
648→// 金額再計算（取引追加・削除後）
649→// ============================================
650→
651→export async function recalcInvoiceGroupTotals(
652→  groupId: number
653→): Promise<void> {
654→  const user = await requireEdit("stp");
655→
656→  const group = await prisma.invoiceGroup.findUnique({
657→    where: { id: groupId, deletedAt: null },
658→    include: { transactions: { where: { deletedAt: null } } },
659→  });
660→  if (!group) throw new Error("請求グループが見つかりません");
661→
662→  // 仕様9.1準拠: 税率別にグループ小計→一括税額計算（インボイス制度対応）
663→  const { subtotal, taxAmount, totalAmount } = calcGroupTotals(group.transactions);
664→
665→  await prisma.invoiceGroup.update({
666→    where: { id: groupId },
667→    data: {
668→      subtotal,
669→      taxAmount,
670→      totalAmount,
671→      updatedBy: user.id,
672→    },
673→  });
674→
675→  revalidatePath("/stp/finance/invoices");
676→}
677→
678→// ============================================
679→// PDF生成・保存
680→// ============================================
681→
682→export async function generateInvoicePdf(
683→  groupId: number
684→): Promise<{ pdfPath: string; invoiceNumber: string }> {
685→  const user = await requireEdit("stp");
686→
687→  // 動的importでサーバー専用モジュールを遅延ロード
688→  const { getInvoicePdfData, generateInvoicePdfBuffer } = await import(
689→    "@/lib/invoices/pdf-generator"
690→  );
691→
692→  const result = await prisma.$transaction(async (tx) => {
693→    const group = await tx.invoiceGroup.findUnique({
694→      where: { id: groupId, deletedAt: null },
695→    });
696→    if (!group) throw new Error("請求グループが見つかりません");
697→
698→    // draft または pdf_created のみPDF生成可能
699→    if (!["draft", "pdf_created"].includes(group.status)) {
700→      throw new Error("このステータスではPDFを生成できません");
701→    }
702→
703→    // 請求書番号を採番（未採番の場合）
704→    let invoiceNumber = group.invoiceNumber;
705→    if (!invoiceNumber) {
706→      invoiceNumber = await generateInvoiceGroupNumber(
707→        group.operatingCompanyId,
708→        tx
709→      );
710→      await tx.invoiceGroup.update({
711→        where: { id: groupId },
712→        data: { invoiceNumber },
713→      });
714→    }
715→
716→    return { invoiceNumber, operatingCompanyId: group.operatingCompanyId };
717→  });
718→
719→  // PDF生成（トランザクション外: DB読取のみ）
720→  const data = await getInvoicePdfData(groupId);
721→  // 採番済み番号を反映
722→  data.invoiceNumber = result.invoiceNumber;
723→
724→  const buffer = await generateInvoicePdfBuffer(data);
725→
726→  // ファイル保存
727→  const now = new Date();
728→  const yearMonth = `${now.getFullYear()}/${String(now.getMonth() + 1).padStart(2, "0")}`;
729→  const uploadDir = path.join(
730→    process.cwd(),
731→    "public/uploads/invoices",
732→    yearMonth
733→  );
734→  await fs.mkdir(uploadDir, { recursive: true });
735→
736→  const pdfFileName = `invoice-${groupId}-${Date.now()}.pdf`;
737→  const filePath = path.join(uploadDir, pdfFileName);
738→  const publicPath = `/uploads/invoices/${yearMonth}/${pdfFileName}`;
739→
740→  await fs.writeFile(filePath, buffer);
741→
742→  // DB更新: pdfPath, pdfFileName, status
743→  const displayFileName = `請求書_${result.invoiceNumber}.pdf`;
744→  await prisma.invoiceGroup.update({
745→    where: { id: groupId },
746→    data: {
747→      pdfPath: publicPath,
748→      pdfFileName: displayFileName,
749→      status: "pdf_created",
750→      updatedBy: user.id,
751→    },
752→  });
753→
754→  revalidatePath("/stp/finance/invoices");
755→  return { pdfPath: publicPath, invoiceNumber: result.invoiceNumber };
756→}
757→
758→// ============================================
759→// 経理へ引渡
760→// ============================================
761→
762→export async function submitInvoiceGroupToAccounting(
763→  id: number
764→): Promise<void> {
765→  const user = await requireEdit("stp");
766→
767→  const group = await prisma.invoiceGroup.findUnique({
768→    where: { id, deletedAt: null },
769→  });
770→  if (!group) throw new Error("請求グループが見つかりません");
771→
772→  if (group.status !== "sent") {
773→    throw new Error("送付済みの請求グループのみ経理へ引き渡せます");
774→  }
775→
776→  const oldStatus = group.status;
777→  await prisma.$transaction(async (tx) => {
778→    await tx.invoiceGroup.update({
779→      where: { id },
780→      data: { status: "awaiting_accounting", updatedBy: user.id },
781→    });
782→
783→    await recordChangeLog(
784→      {
785→        tableName: "InvoiceGroup",
786→        recordId: id,
787→        changeType: "update",
788→        oldData: { status: oldStatus },
789→        newData: { status: "awaiting_accounting" },
790→      },
791→      user.id,
792→      tx
793→    );
794→  });
795→
796→  revalidatePath("/stp/finance/invoices");
797→}
