148→        transactionIds: Array.from(selectedTransactionIds),
149→      });
150→      onClose();
151→    } catch (e) {
152→      alert(e instanceof Error ? e.message : "エラーが発生しました");
153→    } finally {
154→      setLoading(false);
155→    }
156→  };
157→
158→  const canGoToStep2 = !!counterpartyId;
159→  const canGoToStep3 = selectedTransactionIds.size > 0;
160→  const canSubmit =
161→    !!operatingCompanyId && selectedTransactionIds.size > 0;
162→
163→  return (
164→    <Dialog open={open} onOpenChange={onClose}>
165→      <DialogContent className="max-w-3xl max-h-[80vh] flex flex-col">
166→        <DialogHeader>
167→          <DialogTitle>
