277→                            {t.note}
278→                          </div>
279→                        )}
280→                      </div>
281→                      <div className="text-right">
282→                        <div className="text-sm font-medium">
283→                          ¥{t.amount.toLocaleString()}
284→                        </div>
285→                        <div className="text-xs text-muted-foreground">
286→                          税¥{t.taxAmount.toLocaleString()} ({t.taxRate}%)
287→                        </div>
288→                      </div>
289→                    </label>
290→                  ))}
291→                </div>
292→              )}
293→
294→              {/* 選択サマリー */}
295→              {selectedTransactionIds.size > 0 && (
296→                <div className="rounded-lg bg-blue-50 p-3">
297→                  <div className="flex items-center justify-between text-sm">
298→                    <span>{selectedSummary.count}件選択中</span>
299→                    <div className="text-right">
300→                      <div>
301→                        小計: ¥{selectedSummary.subtotal.toLocaleString()}
302→                      </div>
303→                      <div>税: ¥{selectedSummary.tax.toLocaleString()}</div>
304→                      <div className="font-bold">
305→                        合計: ¥{selectedSummary.total.toLocaleString()}
306→                      </div>
307→                    </div>
308→                  </div>
309→                </div>
310→              )}
311→            </div>
312→          )}
313→
314→          {/* Step 3: 請求情報設定 */}
315→          {step === "info" && (
316→            <div className="space-y-4 p-1">
317→              <div className="rounded-lg bg-gray-50 p-3 text-sm">
318→                <div className="flex items-center justify-between">
319→                  <span>
320→                    取引先:{" "}
321→                    {
322→                      counterpartyOptions.find(
323→                        (o) => o.value === counterpartyId
324→                      )?.label
325→                    }
326→                  </span>
327→                  <span>{selectedSummary.count}件の取引</span>
328→                </div>
329→                <div className="text-right font-bold mt-1">
330→                  合計: ¥{selectedSummary.total.toLocaleString()}
331→                </div>
332→              </div>
333→
334→              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
335→                <div>
336→                  <Label htmlFor="operatingCompanyId">請求元法人 *</Label>
337→                  <select
338→                    id="operatingCompanyId"
339→                    value={operatingCompanyId}
340→                    onChange={(e) => {
341→                      setOperatingCompanyId(e.target.value);
342→                      setBankAccountId("");
343→                    }}
344→                    className="mt-1 w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
345→                  >
346→                    {operatingCompanyOptions.map((o) => (
347→                      <option key={o.value} value={o.value}>
348→                        {o.label}
349→                      </option>
350→                    ))}
351→                  </select>
352→                </div>
353→
354→                <div>
355→                  <Label htmlFor="bankAccountId">振込先口座</Label>
356→                  <select
357→                    id="bankAccountId"
358→                    value={bankAccountId}
359→                    onChange={(e) => setBankAccountId(e.target.value)}
360→                    className="mt-1 w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
361→                  >
362→                    <option value="">選択してください</option>
363→                    {currentBankAccounts.map((o) => (
364→                      <option key={o.value} value={o.value}>
365→                        {o.label}
366→                      </option>
367→                    ))}
368→                  </select>
369→                </div>
370→
371→                <div>
372→                  <Label htmlFor="invoiceDate">請求日</Label>
373→                  <Input
374→                    id="invoiceDate"
375→                    type="date"
376→                    value={invoiceDate}
377→                    onChange={(e) => setInvoiceDate(e.target.value)}
378→                    className="mt-1"
379→                  />
380→                </div>
381→
382→                <div>
383→                  <Label htmlFor="paymentDueDate">支払期限</Label>
384→                  <Input
385→                    id="paymentDueDate"
386→                    type="date"
387→                    value={paymentDueDate}
388→                    onChange={(e) => setPaymentDueDate(e.target.value)}
389→                    className="mt-1"
390→                  />
391→                </div>
392→              </div>
393→            </div>
394→          )}
395→        </div>
396→
397→        <DialogFooter className="gap-2">
398→          {step !== "counterparty" && (
399→            <Button
400→              variant="outline"
401→              onClick={() =>
402→                setStep(step === "info" ? "transactions" : "counterparty")
403→              }
404→            >
405→              <ChevronLeft className="mr-1 h-4 w-4" />
406→              戻る
407→            </Button>
408→          )}
409→          <Button variant="outline" onClick={onClose}>
410→            キャンセル
411→          </Button>
412→          {step === "counterparty" && (
413→            <Button
414→              onClick={() => setStep("transactions")}
415→              disabled={!canGoToStep2}
416→            >
417→              次へ
418→              <ChevronRight className="ml-1 h-4 w-4" />
419→            </Button>
420→          )}
421→          {step === "transactions" && (
422→            <Button
423→              onClick={() => setStep("info")}
424→              disabled={!canGoToStep3}
425→            >
426→              次へ
427→              <ChevronRight className="ml-1 h-4 w-4" />
428→            </Button>
429→          )}
430→          {step === "info" && (
431→            <Button onClick={handleCreate} disabled={loading || !canSubmit}>
432→              {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
433→              作成
434→            </Button>
435→          )}
436→        </DialogFooter>
437→      </DialogContent>
438→    </Dialog>
439→  );
440→}
