  1→"use server";
  2→
  3→import { prisma } from "@/lib/prisma";
  4→import { revalidatePath } from "next/cache";
  5→import { requireEdit } from "@/lib/auth";
  6→import { recordChangeLog } from "@/app/accounting/changelog/actions";
  7→
  8→// ============================================
  9→// 型定義
 10→// ============================================
 11→
 12→export type PaymentGroupListItem = {
 13→  id: number;
 14→  counterpartyId: number;
 15→  counterpartyName: string;
 16→  operatingCompanyId: number;
 17→  operatingCompanyName: string;
 18→  targetMonth: string; // YYYY-MM
 19→  expectedPaymentDate: string | null;
 20→  actualPaymentDate: string | null;
 21→  totalAmount: number | null;
 22→  taxAmount: number | null;
 23→  requestedPdfName: string | null;
 24→  receivedPdfPath: string | null;
 25→  receivedPdfFileName: string | null;
 26→  status: string;
 27→  confirmedByName: string | null;
 28→  confirmedAt: string | null;
 29→  transactionCount: number;
 30→  createdByName: string;
 31→  createdAt: string;
 32→};
 33→
 34→export type UngroupedExpenseTransaction = {
 35→  id: number;
 36→  type: string;
 37→  counterpartyId: number;
 38→  counterpartyName: string;
 39→  expenseCategoryName: string;
 40→  amount: number;
 41→  taxAmount: number;
 42→  taxRate: number;
 43→  taxType: string;
 44→  periodFrom: string;
 45→  periodTo: string;
 46→  note: string | null;
 47→};
 48→
 49→// ============================================
 50→// 一覧取得
 51→// ============================================
 52→
 53→export async function getPaymentGroups(): Promise<PaymentGroupListItem[]> {
 54→  const records = await prisma.paymentGroup.findMany({
 55→    where: { deletedAt: null },
 56→    include: {
 57→      counterparty: true,
 58→      operatingCompany: true,
 59→      transactions: { where: { deletedAt: null }, select: { id: true } },
 60→      creator: true,
 61→      confirmer: true,
 62→    },
 63→    orderBy: [{ createdAt: "desc" }, { id: "desc" }],
 64→  });
 65→
 66→  return records.map((r) => ({
 67→    id: r.id,
 68→    counterpartyId: r.counterpartyId,
 69→    counterpartyName: r.counterparty.name,
 70→    operatingCompanyId: r.operatingCompanyId,
 71→    operatingCompanyName: r.operatingCompany.companyName,
 72→    targetMonth: r.targetMonth.toISOString().slice(0, 7), // YYYY-MM
 73→    expectedPaymentDate:
 74→      r.expectedPaymentDate?.toISOString().split("T")[0] ?? null,
 75→    actualPaymentDate:
 76→      r.actualPaymentDate?.toISOString().split("T")[0] ?? null,
 77→    totalAmount: r.totalAmount,
 78→    taxAmount: r.taxAmount,
 79→    requestedPdfName: r.requestedPdfName,
 80→    receivedPdfPath: r.receivedPdfPath,
 81→    receivedPdfFileName: r.receivedPdfFileName,
 82→    status: r.status,
 83→    confirmedByName: r.confirmer?.name ?? null,
 84→    confirmedAt: r.confirmedAt?.toISOString().split("T")[0] ?? null,
 85→    transactionCount: r.transactions.length,
 86→    createdByName: r.creator.name,
 87→    createdAt: r.createdAt.toISOString().split("T")[0],
 88→  }));
 89→}
 90→
 91→// ============================================
 92→// 未グループ化の経費取引を取得
 93→// ============================================
 94→
 95→export async function getUngroupedExpenseTransactions(
 96→  counterpartyId?: number
 97→): Promise<UngroupedExpenseTransaction[]> {
 98→  const where: Record<string, unknown> = {
 99→    deletedAt: null,
100→    type: "expense",
101→    status: "confirmed",
102→    paymentGroupId: null,
103→  };
104→  if (counterpartyId) {
105→    where.counterpartyId = counterpartyId;
106→  }
107→
108→  const records = await prisma.transaction.findMany({
109→    where,
110→    include: {
111→      counterparty: true,
112→      expenseCategory: true,
113→    },
114→    orderBy: [{ periodFrom: "asc" }, { id: "asc" }],
115→  });
116→
117→  return records.map((r) => ({
118→    id: r.id,
119→    type: r.type,
120→    counterpartyId: r.counterpartyId,
121→    counterpartyName: r.counterparty.name,
122→    expenseCategoryName: r.expenseCategory.name,
123→    amount: r.amount,
124→    taxAmount: r.taxAmount,
125→    taxRate: r.taxRate,
126→    taxType: r.taxType,
127→    periodFrom: r.periodFrom.toISOString().split("T")[0],
128→    periodTo: r.periodTo.toISOString().split("T")[0],
129→    note: r.note,
130→  }));
131→}
132→
133→// ============================================
134→// 作成
135→// ============================================
136→
137→export async function createPaymentGroup(data: {
138→  counterpartyId: number;
139→  operatingCompanyId: number;
140→  targetMonth: string; // YYYY-MM
141→  expectedPaymentDate?: string | null;
142→  requestedPdfName?: string | null;
143→  transactionIds: number[];
144→}): Promise<{ id: number }> {
145→  const user = await requireEdit("stp");
146→
147→  const result = await prisma.$transaction(async (tx) => {
148→    // 選択された取引を検証
149→    const transactions = await tx.transaction.findMany({
150→      where: {
151→        id: { in: data.transactionIds },
152→        deletedAt: null,
153→        status: "confirmed",
154→        paymentGroupId: null,
155→        type: "expense",
156→      },
157→    });
158→
159→    if (transactions.length === 0) {
160→      throw new Error("グループ化できる取引がありません");
161→    }
162→
163→    // 全取引が同一取引先か確認
164→    const counterpartyIds = new Set(transactions.map((t) => t.counterpartyId));
165→    if (counterpartyIds.size > 1) {
166→      throw new Error(
167→        "異なる取引先の取引は同じ支払グループに入れられません"
168→      );
169→    }
170→    if (!counterpartyIds.has(data.counterpartyId)) {
171→      throw new Error("取引先が一致しません");
172→    }
173→
174→    // 金額計算
175→    let subtotal = 0;
176→    let taxTotal = 0;
177→    for (const t of transactions) {
178→      if (t.taxType === "tax_excluded") {
179→        subtotal += t.amount;
180→        taxTotal += t.taxAmount;
181→      } else {
182→        // 内税の場合: 金額から税額を引いたのが小計
183→        subtotal += t.amount - t.taxAmount;
184→        taxTotal += t.taxAmount;
185→      }
186→    }
187→
188→    // PaymentGroup作成
189→    const group = await tx.paymentGroup.create({
190→      data: {
191→        counterpartyId: data.counterpartyId,
192→        operatingCompanyId: data.operatingCompanyId,
193→        targetMonth: new Date(data.targetMonth + "-01"),
194→        expectedPaymentDate: data.expectedPaymentDate
195→          ? new Date(data.expectedPaymentDate)
196→          : null,
197→        requestedPdfName: data.requestedPdfName ?? null,
198→        totalAmount: subtotal + taxTotal,
199→        taxAmount: taxTotal,
200→        status: "before_request",
201→        createdBy: user.id,
202→      },
203→    });
204→
205→    // 取引をグループに紐づけ
206→    await tx.transaction.updateMany({
207→      where: { id: { in: data.transactionIds } },
208→      data: { paymentGroupId: group.id },
209→    });
210→
211→    return { id: group.id };
212→  });
213→
214→  revalidatePath("/stp/finance/payment-groups");
215→  revalidatePath("/stp/finance/transactions");
216→  return result;
217→}
218→
219→// ============================================
220→// 更新
221→// ============================================
222→
223→export async function updatePaymentGroup(
224→  id: number,
225→  data: {
226→    expectedPaymentDate?: string | null;
227→    requestedPdfName?: string | null;
228→  }
229→): Promise<void> {
230→  const user = await requireEdit("stp");
231→
232→  const group = await prisma.paymentGroup.findUnique({
233→    where: { id, deletedAt: null },
234→  });
235→  if (!group) throw new Error("支払グループが見つかりません");
236→
237→  // before_request, rejected のみ編集可能
238→  if (!["before_request", "rejected"].includes(group.status)) {
239→    throw new Error("このステータスでは編集できません");
240→  }
241→
242→  const updateData: Record<string, unknown> = {
243→    updatedBy: user.id,
244→  };
245→
246→  if ("expectedPaymentDate" in data)
247→    updateData.expectedPaymentDate = data.expectedPaymentDate
248→      ? new Date(data.expectedPaymentDate)
249→      : null;
250→  if ("requestedPdfName" in data)
251→    updateData.requestedPdfName = data.requestedPdfName ?? null;
252→
253→  await prisma.paymentGroup.update({
254→    where: { id },
255→    data: updateData,
256→  });
257→
258→  revalidatePath("/stp/finance/payment-groups");
259→}
260→
261→// ============================================
262→// 削除（論理削除）
263→// ============================================
264→
265→export async function deletePaymentGroup(
266→  id: number,
267→  deleteTransactions?: boolean
268→): Promise<void> {
269→  const user = await requireEdit("stp");
270→
271→  const group = await prisma.paymentGroup.findUnique({
272→    where: { id, deletedAt: null },
273→  });
274→  if (!group) throw new Error("支払グループが見つかりません");
275→
276→  // before_request のみ削除可能
277→  if (group.status !== "before_request") {
278→    throw new Error(
279→      "「依頼前」ステータスの支払グループのみ削除できます"
280→    );
281→  }
282→
283→  await prisma.$transaction(async (tx) => {
284→    if (deleteTransactions) {
285→      // 紐づく取引も論理削除
286→      await tx.transaction.updateMany({
287→        where: { paymentGroupId: id, deletedAt: null },
288→        data: { deletedAt: new Date(), paymentGroupId: null },
289→      });
290→    } else {
291→      // 取引のグループ紐付けを解除
292→      await tx.transaction.updateMany({
293→        where: { paymentGroupId: id },
294→        data: { paymentGroupId: null },
295→      });
296→    }
297→
298→    // 論理削除
299→    await tx.paymentGroup.update({
300→      where: { id },
301→      data: { deletedAt: new Date(), updatedBy: user.id },
302→    });
303→  });
304→
305→  revalidatePath("/stp/finance/payment-groups");
306→  revalidatePath("/stp/finance/transactions");
307→}
