441→
442→  // 遷移バリデーション
443→  const validTransitions: Record<string, string[]> = {
444→    before_request: ["requested"],
445→    requested: ["invoice_received"],
446→    invoice_received: ["confirmed", "rejected"],
447→    rejected: ["re_requested"],
