481→export async function addTransactionToPaymentGroup(
482→  groupId: number,
483→  transactionIds: number[]
484→): Promise<void> {
485→  const user = await requireEdit("stp");
486→
487→  const group = await prisma.paymentGroup.findUnique({
488→    where: { id: groupId, deletedAt: null },
489→    include: { transactions: { where: { deletedAt: null } } },
490→  });
491→  if (!group) throw new Error("支払グループが見つかりません");
492→
493→  // before_request, rejected のみ追加可能
494→  if (!["before_request", "rejected"].includes(group.status)) {
495→    throw new Error("このステータスでは取引を追加できません");
496→  }
497→
498→  // 追加する取引を検証
499→  const transactions = await prisma.transaction.findMany({
500→    where: {
501→      id: { in: transactionIds },
502→      deletedAt: null,
503→      status: "confirmed",
504→      paymentGroupId: null,
505→      type: "expense",
506→      counterpartyId: group.counterpartyId,
507→    },
508→  });
509→
510→  if (transactions.length === 0) {
511→    throw new Error("追加できる取引がありません");
512→  }
513→
514→  await prisma.$transaction(async (tx) => {
515→    // 取引をグループに紐づけ
516→    await tx.transaction.updateMany({
