518→      data: { paymentGroupId: groupId },
519→    });
520→
521→    // 金額再計算
522→    const allTransactions = [...group.transactions, ...transactions];
523→    let subtotal = 0;
524→    let taxTotal = 0;
525→    for (const t of allTransactions) {
526→      if (t.taxType === "tax_excluded") {
527→        subtotal += t.amount;
528→        taxTotal += t.taxAmount;
529→      } else {
530→        subtotal += t.amount - t.taxAmount;
531→        taxTotal += t.taxAmount;
532→      }
533→    }
534→
535→    await tx.paymentGroup.update({
536→      where: { id: groupId },
537→      data: {
538→        totalAmount: subtotal + taxTotal,
539→        taxAmount: taxTotal,
540→        updatedBy: user.id,
541→      },
542→    });
543→  });
544→
545→  revalidatePath("/stp/finance/payment-groups");
546→  revalidatePath("/stp/finance/transactions");
