628→    include: { expenseCategory: true },
629→    orderBy: [{ periodFrom: "asc" }, { id: "asc" }],
630→  });
631→
632→  return records.map((r) => ({
633→    id: r.id,
634→    expenseCategoryName: r.expenseCategory.name,
635→    amount: r.amount,
636→    taxAmount: r.taxAmount,
637→    taxRate: r.taxRate,
638→    taxType: r.taxType,
639→    periodFrom: r.periodFrom.toISOString().split("T")[0],
640→    periodTo: r.periodTo.toISOString().split("T")[0],
641→    note: r.note,
642→  }));
