644→
645→// ============================================
646→// 経理へ引渡（awaiting_accounting へ遷移）
647→// ============================================
648→
649→export async function submitPaymentGroupToAccounting(
650→  id: number
651→): Promise<void> {
652→  const user = await requireEdit("stp");
653→
654→  const group = await prisma.paymentGroup.findUnique({
655→    where: { id, deletedAt: null },
656→    include: {
657→      transactions: {
658→        where: { deletedAt: null },
659→        include: {
660→          allocationTemplate: {
661→            include: {
662→              lines: { where: { costCenterId: { not: null } } },
663→            },
664→          },
665→          allocationConfirmations: true,
666→        },
667→      },
668→    },
669→  });
670→  if (!group) throw new Error("支払グループが見つかりません");
671→
672→  // confirmed のみ遷移可能
673→  if (group.status !== "confirmed") {
674→    throw new Error(
675→      "「確認済み」ステータスの支払のみ経理へ引渡できます"
676→    );
677→  }
678→
679→  // 按分確定チェック: allocationTemplateId がある取引は全プロジェクトの按分確定が必要
680→  for (const tx of group.transactions) {
681→    if (tx.allocationTemplateId && tx.allocationTemplate) {
682→      const requiredCostCenterIds = tx.allocationTemplate.lines
683→        .filter((line) => line.costCenterId !== null)
684→        .map((line) => line.costCenterId!);
685→
686→      const confirmedCostCenterIds = new Set(
687→        tx.allocationConfirmations
688→          .filter((ac) => ac.confirmedAt !== null)
689→          .map((ac) => ac.costCenterId)
690→      );
691→
692→      const allConfirmed = requiredCostCenterIds.every((ccId) =>
693→        confirmedCostCenterIds.has(ccId)
694→      );
695→
696→      if (!allConfirmed) {
697→        throw new Error(
698→          "按分確定が完了していない取引が含まれています。全プロジェクトの按分確定を完了してください。"
699→        );
700→      }
701→    }
702→  }
703→
704→  await prisma.$transaction(async (tx) => {
705→    await tx.paymentGroup.update({
706→      where: { id },
707→      data: {
708→        status: "awaiting_accounting",
709→        updatedBy: user.id,
710→      },
711→    });
712→
713→    await recordChangeLog(
714→      {
715→        tableName: "PaymentGroup",
716→        recordId: id,
717→        changeType: "update",
718→        oldData: { status: group.status },
719→        newData: { status: "awaiting_accounting" },
720→      },
721→      user.id,
722→      tx
723→    );
724→  });
725→
726→  revalidatePath("/stp/finance/payment-groups");
727→}
