    Set<number>
  >(new Set());

  // Step 3: 請求情報
  const [operatingCompanyId, setOperatingCompanyId] = useState<string>(
    operatingCompanyOptions[0]?.value ?? ""
  );
  const [bankAccountId, setBankAccountId] = useState<string>("");
