            </Button>
          )}
          {step === "info" && (
            <Button onClick={handleCreate} disabled={loading || !canSubmit}>
              {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              作成
            </Button>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
