export function PaymentGroupsPageClient({
  data,
  ungroupedTransactions,
  counterpartyOptions,
  operatingCompanyOptions,
}: Props) {
  const [activeTab, setActiveTab] = useState<string>(
    ungroupedTransactions.length > 0 ? "ungrouped" : "list"
  );

